#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    double charges[N];
    for (int i = 0; i < N; i++) {
        scanf("%lf", &charges[i]);
    }
    double forces[N];
    for (int i = 0; i < N; i++) {
        forces[i] = 0;
        for (int j = 0; j < N; j++) {
            if (i != j) {
                double distance = i - j;
                forces[i] += 50 * charges[i] * charges[j] / (distance * distance);
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%f\n", forces[i]);
    }
    return 0;
}

