import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        double[] charges = new double[N];
        for (int i = 0; i < N; i++) {
            charges[i] = scanner.nextDouble();
        }
        double[] forces = new double[N];
        for (int i = 0; i < N; i++) {
            forces[i] = 0;
            for (int j = 0; j < N; j++) {
                if (i != j) {
                    double distance = i - j;
                    forces[i] += 50 * charges[i] * charges[j] / (distance * distance);
                }
            }
        }
        for (int i = 0; i < N; i++) {
            System.out.println(forces[i]);
        }
    }
}

